42	    extern __shared__ __align__(ptx::kNumTMAAlignBytes) int8_t smem[];
43	    const auto comm_token_layout = layout::TokenLayout(kNumHiddenBytes, 0, kNumTopk, false);
44	    const auto comm_buffer = layout::BufferLayout<false>(
45	        comm_token_layout, kNumTokensInLayout, kNumMaxTokensPerRank, recv_buffer);
46	
47	    // Store buffers
48	    const auto output_token_layout = layout::TokenLayout(kNumHiddenBytes, 0, 0, false);
49	    const auto output_buffer = layout::BufferLayout<false>(output_token_layout, 1, num_combined_tokens, combined_x);
50	    const auto tma_buffer = layout::BufferLayout<false>(output_token_layout, kNumWarps, 1, smem)
51	        .get_rank_buffer(warp_idx).get_token_buffer(0);
52	
53	    // Bias layout
54	    const auto bias_0_buffer = layout::BufferLayout<false>(output_token_layout, 1, num_combined_tokens, bias_0);
55	    const auto bias_1_buffer = layout::BufferLayout<false>(output_token_layout, 1, num_combined_tokens, bias_1);
56	
