58	    // NOTES: PDL is used, please do not use `__ldg`
59	    cudaGridDependencySynchronize();
60	
61	    // Read from buffers and do reduction
62	    for (int token_idx = global_warp_idx; token_idx < num_combined_tokens; token_idx += kNumWarps * kNumSMs) {
63	        // Preprocess all indices
64	        int stored_dst_rank_idx = -1, stored_dst_expert_idx = -1;
65	        EP_STATIC_ASSERT(kNumTopk <= 32, "Too many top-k selections");
66	        if (lane_idx < kNumTopk) {
67	            stored_dst_expert_idx = static_cast<int>(combined_topk_idx[token_idx * kNumTopk + lane_idx]);
68	            stored_dst_rank_idx = stored_dst_expert_idx >= 0 ?
69	                stored_dst_expert_idx / (kNumScaleoutRanks == 1 ? kNumExpertsPerRank : kNumExpertsPerScaleout) : -1;
70	        }
71	        __syncwarp();
72	
73	        // Sort valid top-k indices to front
74	        const auto [should_deduplicate, deduplicate_key] = [&]() -> std::pair<bool, int> {
75	            if constexpr (kUseExpandedLayout and not kAllowMultipleReduction) {
76	                // Activations are never reduced before
77	                return {false, 0};
78	            } else if constexpr (kNumScaleoutRanks != 1 and not kUseExpandedLayout and not kAllowMultipleReduction) {
79	                // Hybrid mode without expanded layout and multiple reduction. Should deduplicate on a per-rank basis
80	                return {true, stored_dst_expert_idx >= 0 ? stored_dst_expert_idx / kNumExpertsPerRank : -1};
81	            } else {
82	                // Should deduplicate on a per-rank (for non-hybrid mode) or a per-scale-rank (for hybrid mode) basis
83	                return {true, stored_dst_rank_idx};
84	            }
85	        }();
