1	#pragma once
2	
3	#include <stdexcept>
4	
5	
6	namespace deep_ep::elastic {
7	
8	template <bool kAllowMultipleReduction, int kNumRanks, int kNumTopk>
9	constexpr bool use_rank_layout() {
10	    if constexpr (not kAllowMultipleReduction)
11	        return false;
12	    return kNumRanks <= kNumTopk;
13	}
14	
15	template <bool kAllowMultipleReduction, int kNumRanks, int kNumTopk>
16	constexpr int get_num_tokens_in_layout() {
17	    return use_rank_layout<kAllowMultipleReduction, kNumRanks, kNumTopk>() ? kNumRanks : kNumTopk;
18	}
19	
20	template <int kLength, int kMaxUnrollFactor, int kWarpSize = 32>
21	constexpr int get_max_unroll_factor() {
22	    for (int i = kMaxUnrollFactor; i >= 1; -- i)
23	        if (kLength % (kWarpSize * i) == 0)
24	            return i;
25	    throw std::logic_error("Invalid length, cannot find unrolling factor");
26	}
27	
28	// Determine the vector type for combine loads/stores based on arch and hidden size alignment
29	template <int kHiddenBytes>
30	struct CombineVecTraits {
31	#if defined(__CUDA_ARCH__) and (__CUDA_ARCH__ >= 1000)
32	    // On SM100+, use `longlong4_t` (32 bytes) if hidden is aligned, otherwise fall back to `int4` (16 bytes)
33	    // NOTES: we observe some performance degrade with `longlong4_t`, temporarily disable it
34	    static constexpr bool kUseLonglong4 = false;
35	    using vec_t = std::conditional_t<kUseLonglong4, longlong4_t, int4>;
36	#else
37	    using vec_t = int4;
38	#endif
39	};
40	
41	template <int kNumValidTopk, typename fetch_func_t>
42	__device__ __forceinline__
43	void compute_topk_slots(int (&topk_slot_idx)[kNumValidTopk], uint32_t mask,
44	                        const fetch_func_t& fetch_func) {
45	    #pragma unroll
46	    for (int k = 0; k < kNumValidTopk; ++ k) {
47	        const int lowest_idx = __ffs(mask) - 1;
48	        // Here we perform the exchange unconditionally to avoid `BRA.DIV`
49	        const auto fetched = fetch_func(lowest_idx);
50	        mask &= mask - 1;
51	        topk_slot_idx[k] = lowest_idx >= 0 ? fetched : -1;
52	    }
53	}
54	
55	template <int kHiddenVec, int kUnrollFactor, int kNumExpectedTopk, int kNumValidTopk,
56	          typename vec_t, typename get_src_buffer_ptr_func_t, typename wait_buffer_func_t>
57	__device__ __forceinline__
58	void combine_reduce(const int& lane_idx, int (&topk_slot_idx)[kNumValidTopk],
59	                    vec_t* dst_buffer_ptr,
60	                    const get_src_buffer_ptr_func_t& get_src_buffer_ptr_func,
61	                    const wait_buffer_func_t& wait_buffer_func,
62	                    vec_t* bias_0 = nullptr, vec_t* bias_1 = nullptr) {
63	    constexpr int kNumElemsPerVec = sizeof(vec_t) / sizeof(nv_bfloat16);
64	    EP_STATIC_ASSERT(kNumElemsPerVec % 2 == 0, "Invalid number of elements");
65	    EP_STATIC_ASSERT(kHiddenVec % (kUnrollFactor * 32) == 0, "Invalid unrolling");
66	
67	    // We use BF16 add as much as possible, as casting is slow
68	    const bool enable_hadd_bypass =
69	        (bias_0 == nullptr and bias_1 == nullptr) and
70	        (kNumValidTopk <= 2 or topk_slot_idx[2] < 0);
71	    EP_STATIC_ASSERT(kNumValidTopk > 0, "Invalid top-k");
72	
73	    if (enable_hadd_bypass) {
74	        #pragma unroll 1
75	        for (int i = 0; i < kHiddenVec / (kUnrollFactor * 32); ++ i) {
76	            // Read values 0
77	            const auto slot_0 = topk_slot_idx[0];
78	            const auto src_base_ptr_0 = get_src_buffer_ptr_func(slot_0);
79	            vec_t values_0[kUnrollFactor] = {};
80	            #pragma unroll
81	            for (int j = 0; j < kUnrollFactor; ++ j) {
82	                values_0[j] = ptx::ldg_with_gez_pred(
83	                    src_base_ptr_0 + (i * (kUnrollFactor * 32) + j * 32 + lane_idx), slot_0);
84	            }
85	
86	            // Read values 1
87	            vec_t values_1[kUnrollFactor] = {};
88	            const auto slot_1 = kNumValidTopk == 1 ? -1 : topk_slot_idx[1];
89	            const auto src_base_ptr_1 = get_src_buffer_ptr_func(slot_1);
90	            #pragma unroll
91	            for (int j = 0; j < kUnrollFactor; ++ j) {
92	                values_1[j] = ptx::ldg_with_gez_pred(
93	                    src_base_ptr_1 + (i * (kUnrollFactor * 32) + j * 32 + lane_idx), slot_1);
94	            }
95	
96	            // Wait buffer releases for the first write
97	            if (i == 0)
98	                wait_buffer_func();
99	
100	            // Reduce into shared memory
101	            const auto bf162_view_0 = reinterpret_cast<nv_bfloat162*>(values_0);
102	            const auto bf162_view_1 = reinterpret_cast<nv_bfloat162*>(values_1);
103	            #pragma unroll
104	            for (int j = 0; j < kUnrollFactor; ++ j) {
105	                #pragma unroll
106	                for (int l = 0; l < kNumElemsPerVec / 2; ++ l)
107	                    bf162_view_0[j * (kNumElemsPerVec / 2) + l] += bf162_view_1[j * (kNumElemsPerVec / 2) + l];
108	                dst_buffer_ptr[i * (kUnrollFactor * 32) + j * 32 + lane_idx] = values_0[j];
109	            }
110	        }
111	    } else {
112	        #pragma unroll 1
113	        for (int i = 0; i < kHiddenVec / (kUnrollFactor * 32); ++ i) {
114	            // Add bias
115	            float2 reduced[kUnrollFactor * kNumElemsPerVec / 2] = {};
116	            const auto add_bias = [&](const vec_t* base_ptr) {
117	                // Read
118	                vec_t values[kUnrollFactor];
119	                #pragma unroll
120	                for (int j = 0; j < kUnrollFactor; ++ j)
121	                    values[j] = ptx::ldg(base_ptr + i * (kUnrollFactor * 32) + j * 32 + lane_idx);
122	
123	                // Reduce
124	                const auto bf162_view = reinterpret_cast<nv_bfloat162*>(values);
125	                #pragma unroll
126	                for (int j = 0; j < kUnrollFactor * kNumElemsPerVec / 2; ++ j)
127	                    ptx::accumulate(reduced[j], bf162_view[j]);
128	            };
129	            bias_0 != nullptr ? add_bias(bias_0) : void();
130	            bias_1 != nullptr ? add_bias(bias_1) : void();
131	
132	            #pragma unroll
133	            for (int k = 0; k < kNumValidTopk; ++ k) {
134	                // We have a limitation on `k` to reduce the branch instruction count
135	                if (k >= kNumExpectedTopk and topk_slot_idx[k] < 0)
136	                    break;
137	
138	                // Read values
139	                const auto src_base_ptr = get_src_buffer_ptr_func(topk_slot_idx[k]);
140	                vec_t values[kUnrollFactor] = {};
141	                #pragma unroll
142	                for (int j = 0; j < kUnrollFactor; ++ j) {
143	                    values[j] = ptx::ldg_with_gez_pred(
144	                        src_base_ptr + (i * (kUnrollFactor * 32) + j * 32 + lane_idx), topk_slot_idx[k]);
145	                }
146	
147	                // Reduce
148	                const auto bf162_view = reinterpret_cast<nv_bfloat162*>(values);
149	                #pragma unroll
150	                for (int j = 0; j < kUnrollFactor * kNumElemsPerVec / 2; ++ j)
151	                    ptx::accumulate(reduced[j], bf162_view[j]);
152	            }
153	
154	            // Wait buffer releases for the first write
155	            if (i == 0)
156	                wait_buffer_func();
157	
158	            // Cast into shared memory
159	            #pragma unroll
160	            for (int j = 0; j < kUnrollFactor; ++ j) {
161	                vec_t casted_value;
162	                auto bf162_view = reinterpret_cast<nv_bfloat162*>(&casted_value);
163	                #pragma unroll
164	                for (int l = 0; l < kNumElemsPerVec / 2; ++ l)
165	                    bf162_view[l] = __float22bfloat162_rn(reduced[j * (kNumElemsPerVec / 2) + l]);
166	                dst_buffer_ptr[i * (kUnrollFactor * 32) + j * 32 + lane_idx] = casted_value;
167	            }
168	        }
169	    }
170	}
171	
172	}  // namespace deep_ep::elastic
