237	        EP_CUDA_UNIFIED_CHECK(jit::launch_kernel(kernel, config,
238	                                                 args.combined_x,
239	                                                 args.combined_topk_weights,
240	                                                 args.combined_topk_idx,
241	                                                 args.reduce_buffer,
242	                                                 args.bias_0, args.bias_1,
243	                                                 args.num_combined_tokens,
244	                                                 args.scaleout_rank_idx, args.scaleup_rank_idx));
245	    }
246	};
247	
248	static void launch_combine_reduce_epilogue(void* combined_x,
249	                                           float* combined_topk_weights,
250	                                           topk_idx_t* combined_topk_idx,
251	                                           const int& num_combined_tokens, const int& num_max_tokens_per_rank,
252	                                           const int& hidden,
253	                                           const int& num_experts, const int& num_topk,
254	                                           void* reduce_buffer,
255	                                           void* bias_0, void* bias_1,
256	                                           const int& num_scaleout_ranks, const int& num_scaleup_ranks,
257	                                           const int& scaleout_rank_idx, const int& scaleup_rank_idx,
258	                                           const int& num_sms, const int& num_smem_bytes,
259	                                           const bool& use_expanded_layout, const bool& allow_multiple_reduction,
260	                                           const at::cuda::CUDAStream& stream) {
261	    // Maximize shared memory utilization
262	    // Too many warps may cause performance degrade, so we limit into 1024
263	    const auto token_layout = layout::TokenLayout(hidden * sizeof(nv_bfloat16), 0, 0, false);
264	    const auto num_warps = std::min<int>(num_smem_bytes / token_layout.get_num_bytes<false>(), 32);
265	    const auto num_threads = num_warps * 32;
266	
267	    // Generate, build and launch
268	    const CombineReduceEpilogueRuntime::Args args = {
269	        .use_expanded_layout = use_expanded_layout,
270	        .allow_multiple_reduction = allow_multiple_reduction,
271	        .num_scaleout_ranks = num_scaleout_ranks, .num_scaleup_ranks = num_scaleup_ranks,
272	        .hidden = hidden,
273	        .num_max_tokens_per_rank = num_max_tokens_per_rank,
274	        .num_experts = num_experts, .num_topk = num_topk,
275	        .combined_x = static_cast<nv_bfloat16*>(combined_x),
276	        .combined_topk_weights = combined_topk_weights,
277	        .combined_topk_idx = combined_topk_idx,
278	        .reduce_buffer = reduce_buffer,
279	        .bias_0 = bias_0, .bias_1 = bias_1,
280	        .num_combined_tokens = num_combined_tokens,
281	        .scaleout_rank_idx = scaleout_rank_idx, .scaleup_rank_idx = scaleup_rank_idx,
282	        .launch_args = jit::LaunchArgs(num_sms, num_threads, num_smem_bytes, 1, false, true)
283	    };
284	    const auto code = CombineReduceEpilogueRuntime::generate(args);
285	    const auto runtime = jit::compiler->build("combine_reduce_epilogue", code);
286	    CombineReduceEpilogueRuntime::launch(runtime, args, stream);
287	}
