                                   jit::device_runtime->get_num_sms(),
                                   jit::device_runtime->get_num_smem_bytes(),
                                   use_expanded_layout, allow_multiple_reduction,
                                   comm_stream);

    // Stream control
    const auto event = stream_control_epilogue(
